import React, { Component } from "react";
import "./style.css";

export default class extends Component {
  constructor(props, context) {
    super(props, context);
  }

  componentDidMount() {
    // console.log("componentDidMount");
    const loadExternalScript = (src, callback) => {
      // console.log("loadExternalScript: ", src, callback);

      for (var key in src) {
        var value = src[key];
        // console.log("value: ", value);
        //
        const script = document.createElement("script");
        script.async = true;
        script.src = value;
        document.head.appendChild(script); //For head
        // document.body.appendChild(script); // For body
        //
        // console.log("script: ", script);
        script.onload = () => {
          console.log("script.onload: ", script);
          callback();
        };
      }
    };

    const callback = callback => {
      // console.log("callback: ", window);
    };

    callback();

    loadExternalScript(["https://codepen.io/tiggr/pen/poJoLyW.js"], callback);
  }

  render() {
    return (
      <>
        <button
          className="js-toggle-fullscreen-btn toggle-fullscreen-btn"
          aria-label="Enter fullscreen mode"
          hidden
        >
          <svg
            className="toggle-fullscreen-svg"
            width="28"
            height="28"
            viewBox="-2 -2 28 28"
          >
            <g className="icon-fullscreen-enter">
              <path d="M 2 9 v -7 h 7" />
              <path d="M 22 9 v -7 h -7" />
              <path d="M 22 15 v 7 h -7" />
              <path d="M 2 15 v 7 h 7" />
            </g>

            <g className="icon-fullscreen-leave">
              <path d="M 24 17 h -7 v 7" />
              <path d="M 0 17 h 7 v 7" />
              <path d="M 0 7 h 7 v -7" />
              <path d="M 24 7 h -7 v -7" />
            </g>
          </svg>
        </button>

        {/* <article>
          <h1 className="wrap">
            A capacidade da internet de empoderar o indivíduo.
          </h1>
          <div className="wrap">
            <h2>Inspirando Mentes @MOZG</h2>
          </div>
        </article> */}
      </>
    );
  }
}
